import{a as e,c as t,d as n,f as r,u as i,w as a,x as o,y as s}from"./runtime-core.esm-bundler-CD3o_SA6.js";import{t as c}from"./_plugin-vue_export-helper-B80Cc4Ui.js";var l={},u={class:`chapter-header`},d={class:`breadcrumb`},f={class:`page-container`},p={class:`chapter-nav`};function m(c,l){let m=o(`router-link`);return s(),t(`div`,null,[e(`header`,u,[e(`div`,d,[r(m,{to:`/`},{default:a(()=>[...l[0]||=[n(`Study Guide`,-1)]]),_:1}),l[3]||=n(` › `,-1),r(m,{to:`/sa`},{default:a(()=>[...l[1]||=[n(`SA`,-1)]]),_:1}),l[4]||=n(` › `,-1),r(m,{to:`/sa/fundamentals`},{default:a(()=>[...l[2]||=[n(`Fundamentals`,-1)]]),_:1}),l[5]||=n(` › Chapter 2 `,-1)]),l[6]||=i(`<h1>Chapter 2: Architectural Thinking</h1><p class="chapter-desc">Seeing systems from an architect&#39;s eye — understanding the architecture/design spectrum, developing technical breadth, analyzing trade-offs, and staying current through practical habits.</p><div class="stats-bar"><span class="stat-badge">Architecture vs Design</span><span class="stat-badge">Knowledge Pyramid</span><span class="stat-badge">20-Minute Rule</span><span class="stat-badge">Personal Radar</span><span class="stat-badge">Trade-off Analysis</span></div>`,3)]),e(`div`,f,[l[9]||=i(`<div class="toc"><h2>Table of Contents</h2><ol><li><a href="#s2-1">Architecture Versus Design</a></li><li><a href="#s2-2">Technical Breadth</a></li><li><a href="#s2-3">The 20-Minute Rule</a></li><li><a href="#s2-4">Developing a Personal Radar</a></li><li><a href="#s2-5">Analyzing Trade-Offs</a></li><li><a href="#s2-6">Understanding Business Drivers</a></li><li><a href="#s2-7">Balancing Architecture and Hands-On Coding</a></li><li><a href="#takeaways">Key Takeaways</a></li></ol></div><h2 class="section-title" id="s2-1">Architecture Versus Design</h2><div class="content-section"><p>Architecture is about <strong>structure</strong>; design is about <strong>appearance</strong>. But in practice, most decisions fall somewhere on a spectrum between the two. Three criteria help determine where a decision lands:</p><div class="info-box analogy-box"><p><strong>House analogy:</strong> The number of floors, roof style, and number of bedrooms = architecture. The carpet color, wall paint, and light fixtures = design. Choosing microservices vs monolith = architecture. Choosing which CSS framework to use = design. Most decisions fall somewhere in between.</p></div><table class="comparison-table"><thead><tr><th>Criterion</th><th>More Architectural</th><th>More Design</th></tr></thead><tbody><tr><td><strong>Strategic vs Tactical</strong></td><td>Long-term, many stakeholders involved, weeks of planning</td><td>Short-term, made quickly, minimal review</td></tr><tr><td><strong>Level of Effort</strong></td><td>&quot;The stuff that&#39;s hard to change&quot; (Martin Fowler). Significant effort to implement or undo.</td><td>Easy to implement, easy to reverse. Rearranging fields on a screen.</td></tr><tr><td><strong>Trade-off Significance</strong></td><td>Significant impact on scalability, performance, maintainability, cost</td><td>Minor trade-offs, unlikely to cascade across the system</td></tr></tbody></table><p>Architecture and design must collaborate, not compete. The architect defines the constraints and guiding principles; developers make design decisions within those constraints. A good architect establishes a <em>guard rail</em>, not a straight jacket.</p></div><h2 class="section-title" id="s2-2">Technical Breadth</h2><div class="content-section"><p>Architects must shift their professional focus from <strong>depth</strong> to <strong>breadth</strong>. This is one of the hardest transitions to make, and it requires deliberately changing how you invest your learning time.</p><div class="pattern-summary"><h4>The Knowledge Pyramid (three levels)</h4><div class="ps-row"><span class="ps-label">Stuff you know:</span> <span>Technologies you work with daily. Your area of expertise. <em>Technical depth.</em> Smallest section — requires constant maintenance to stay current.</span></div><div class="ps-row"><span class="ps-label">Stuff you know you don&#39;t know:</span> <span>Things you&#39;ve heard of but can&#39;t do. A Clojure programmer who knows Java exists but can&#39;t write Lisp. Larger than &quot;stuff you know.&quot; <em>The architect&#39;s expansion target.</em></span></div><div class="ps-row"><span class="ps-label">Stuff you don&#39;t know you don&#39;t know:</span> <span>The largest area. The perfect solution to your problem may exist here — you just haven&#39;t heard of it yet. Architects must actively move things from this zone into awareness.</span></div></div><div class="info-box note-box"><p><strong>Developer vs Architect knowledge shapes:</strong><br> A developer&#39;s pyramid has a <em>tall, narrow top</em> — deep expertise in a focused area. An architect&#39;s pyramid has a <em>shorter, wider top</em> — less deep in any single area but aware of far more options. The key transition is sacrificing some depth to gain more breadth. This is uncomfortable for people who pride themselves on technical expertise.</p></div><h4 class="subsubsection-title">Frozen Caveman Antipattern</h4><p>An architect who applies old fears or outdated mental models to every new decision. Example: an architect who experienced a network outage years ago becomes obsessed with &quot;What if we lose Italy?&quot; — applying this fear disproportionately to every architecture decision regardless of actual probability. Caused by stale expertise or past trauma.</p><p><strong>The fix:</strong> Continuously update your mental model. Distinguish between genuine risk and perceived risk based on past experience that no longer applies.</p></div><h2 class="section-title" id="s2-3">The 20-Minute Rule</h2><div class="content-section"><p>The most practical habit for building technical breadth: devote <strong>at least 20 minutes every morning</strong> to learning something new, before checking email.</p><div class="info-box key-point-box"><p><strong>Why morning?</strong> Once you check email, your morning is over and your day has started. 20 minutes with a fresh mind — before the first meeting, before the first Slack message — is far more effective than evening sessions when energy is depleted. Pick a consistent time and protect it.</p></div><p>Good sources: <strong>InfoQ</strong>, <strong>DZone Refcardz</strong>, <strong>Thoughtworks Technology Radar</strong>, O&#39;Reilly publications, conference talks. The goal: move things from &quot;stuff you don&#39;t know you don&#39;t know&quot; into &quot;stuff you know you don&#39;t know.&quot;</p></div><h2 class="section-title" id="s2-4">Developing a Personal Radar</h2><div class="content-section"><p>Based on the <a href="https://www.thoughtworks.com/radar" target="_blank">Thoughtworks Technology Radar</a> — a living document for assessing technology risk and value. The Radar uses two dimensions: <em>quadrants</em> (what type of technology) and <em>rings</em> (how strongly to pursue it).</p><table class="comparison-table"><thead><tr><th>Ring</th><th>Meaning (Thoughtworks)</th><th>Personal adaptation</th></tr></thead><tbody><tr><td><strong>Hold</strong></td><td>Don&#39;t start new projects with this. Use on existing only if already committed.</td><td>Habits to break, low-value information streams, technologies to phase out.</td></tr><tr><td><strong>Assess</strong></td><td>Worth exploring — do a spike or conference session to evaluate.</td><td>Promising technologies you&#39;ve heard of but haven&#39;t had time to evaluate yet. A staging area for research.</td></tr><tr><td><strong>Trial</strong></td><td>Worth pursuing. Build a low-risk pilot project.</td><td>Active R&amp;D. Spike experiments. Worth deeper investment to enable effective trade-off analysis.</td></tr><tr><td><strong>Adopt</strong></td><td>Industry should adopt this now.</td><td>Your best practices and most effective tools for solving specific problems.</td></tr></tbody></table><div class="info-box analogy-box"><p><strong>Financial portfolio analogy:</strong> Treat your technology portfolio like investments. Diversify: some widely-demanded skills (stable income), some emerging bets (high upside). Don&#39;t go all-in on one technology — the Clipper story is a cautionary tale: an entire industry&#39;s expertise became worthless literally overnight when Windows replaced DOS.</p></div><p>Thoughtworks provides a free tool called <strong>Build Your Own Radar</strong> — it takes a Google spreadsheet as input and generates a visual radar. The process of building the radar (the thinking it forces) is more valuable than the output itself.</p></div><h2 class="section-title" id="s2-5">Analyzing Trade-Offs</h2><div class="content-section"><p>The most important insight in architectural thinking:</p><div class="info-box key-point-box"><p><strong>&quot;Architecture is the stuff you can&#39;t Google or ask an LLM about.&quot;</strong> — Mark Richards<br><strong>&quot;There are no right or wrong answers in architecture — only trade-offs.&quot;</strong> — Neal Ford</p><p>The correct answer to almost every architecture question is <em>&quot;It depends&quot;</em> — on deployment environment, business drivers, company culture, budgets, timelines, team skill set, and dozens of other context-specific factors.</p></div><h4 class="subsubsection-title">Example: Queues vs Topics in a Bid System</h4><p>An auction system where a Bid Producer service sends bids to multiple downstream services. Two options:</p><table class="comparison-table"><thead><tr><th>Option</th><th>Mechanism</th><th>Benefits</th><th>Drawbacks</th></tr></thead><tbody><tr><td><strong>Point-to-Point (Queues)</strong></td><td>Separate queue per consumer</td><td>Better data access control, monitoring per consumer, guaranteed single consumption</td><td>Tight producer-consumer coupling, harder to add new consumers, duplicate message routing</td></tr><tr><td><strong>Publish-Subscribe (Topics)</strong></td><td>One topic, multiple subscribers</td><td>Easy to add new consumers (open/closed principle), looser coupling, simpler producer</td><td>Less control over who receives data, harder to monitor individual consumers, no guaranteed exclusive delivery</td></tr></tbody></table><p>Neither is universally better. The choice depends on: security requirements, expected number of consumers, monitoring needs, and how often the consumer list changes.</p></div><h2 class="section-title" id="s2-6">Understanding Business Drivers</h2><div class="content-section"><p>Architects must translate business requirements into architectural characteristics. This requires understanding the business domain deeply enough to recognize which &quot;-ilities&quot; matter most for the system.</p><ul><li><strong>Time to market</strong> might translate to: simplicity, deployability, agility</li><li><strong>Regulatory compliance</strong> might translate to: auditability, data residency, security</li><li><strong>Cost reduction</strong> might translate to: efficiency, scalability, cloud readiness</li><li><strong>Customer growth</strong> might translate to: scalability, availability, performance</li></ul></div><h2 class="section-title" id="s2-7">Balancing Architecture and Hands-On Coding</h2><div class="content-section"><p>Architects who lose touch with code lose credibility with developers and make decisions that are disconnected from reality. But getting too deep in the code means neglecting architectural thinking.</p><table class="comparison-table"><thead><tr><th>Approach</th><th>Description</th></tr></thead><tbody><tr><td><strong>Proof of concept (PoC)</strong></td><td>Write throwaway code to validate a risky architectural assumption. Not meant for production — just enough to confirm the approach works.</td></tr><tr><td><strong>Tackle technical debt and bugs</strong></td><td>A great way to contribute code without blocking critical feature work. Gets you into the codebase regularly.</td></tr><tr><td><strong>Automation and tooling</strong></td><td>Build fitness functions, deployment scripts, testing tools — code that helps the team rather than a feature for the user.</td></tr><tr><td><strong>Code reviews</strong></td><td>Stay connected to what&#39;s being built and how, without being a bottleneck on feature delivery.</td></tr></tbody></table></div><div class="takeaways" id="takeaways"><h3>Key Takeaways — Chapter 2</h3><ul><li>Architecture is about <strong>structure</strong>; design is about appearance. Architecture decisions are strategic, hard-to-change, and have significant trade-offs.</li><li>Architects need <strong>technical breadth</strong> more than depth. Know many solutions well enough to evaluate trade-offs, rather than being expert in only one.</li><li>The <strong>knowledge pyramid</strong> has three levels: stuff you know, stuff you know you don&#39;t know, and stuff you don&#39;t know you don&#39;t know. Architects must actively expand the middle layer.</li><li>The <strong>Frozen Caveman antipattern</strong>: applying outdated fears to current decisions. Distinguish genuine from perceived risk.</li><li>The <strong>20-minute rule</strong>: invest 20 minutes every morning in learning something new, before checking email. Small consistent investment compounds dramatically over time.</li><li>A <strong>personal technology radar</strong> (Hold/Assess/Trial/Adopt) helps structure your technology investment decisions. Treat your skills like a financial portfolio.</li><li>There are no right or wrong architecture answers — only trade-offs. The answer to every architecture question is &quot;it depends.&quot; The architect&#39;s job is to identify <em>what</em> it depends on.</li><li>Stay connected to code via PoCs, technical debt work, tooling, and code reviews — but avoid getting so deep in implementation that you lose the architectural perspective.</li></ul></div>`,16),e(`div`,p,[r(m,{to:`/sa/fundamentals/ch1`,class:`prev`},{default:a(()=>[...l[7]||=[n(`← Chapter 1`,-1)]]),_:1}),r(m,{to:`/sa/fundamentals/ch3`,class:`next`},{default:a(()=>[...l[8]||=[n(`Chapter 3 →`,-1)]]),_:1})])])])}var h=c(l,[[`render`,m]]);export{h as default};